arguments.command:
python3 -c "
import json

with open('.template.config/template.json') as f:
    data = json.load(f)

issues = []

# Check required fields
required = ['author', 'classifications', 'name', 'shortName', 'identity']
for field in required:
    if field not in data:
        issues.append(f'Missing required field: \"{field}\"')

# Check sourceName (recommended)
if 'sourceName' not in data:
    issues.append('Missing recommended field: \"sourceName\"')

# Validate symbols
valid_datatypes = ['bool', 'choice', 'float', 'int', 'hex', 'text', 'string']
if 'symbols' in data:
    for name, sym in data['symbols'].items():
        if 'datatype' in sym and sym['datatype'] not in valid_datatypes:
            issues.append(f'Symbol \"{name}\": invalid datatype \"{sym[\"datatype\"]}\". Valid values: {valid_datatypes}')

# Check shortName for reserved names
reserved_short_names = ['build', 'clean', 'help', 'install', 'list', 'new', 'nuget', 'pack', 'publish', 'restore', 'run', 'sln', 'test']
if data.get('shortName') in reserved_short_names:
    issues.append(f'shortName \"{data[\"shortName\"]}\" conflicts with a built-in dotnet CLI command')

for i in issues:
    print(f'  ⚠ {i}')

if not issues:
    print('No issues found.')
else:
    print(f'\n{len(issues)} issue(s) found.')
"

